#pragma once
#define BATTERIES_PROTECTED_MEMORY_HPP

#include <batteries/config.hpp>
//

#include <batteries/buffer.hpp>
#include <batteries/status.hpp>
#include <batteries/strong_typedef.hpp>
#include <batteries/typed_args.hpp>

#if BATT_PLATFORM_IS_LINUX
#include <sys/mman.h>
#endif

namespace batt {

class ProtectedMemory
{
   public:
    using Self = ProtectedMemory;

    BATT_STRONG_TYPEDEF(bool, DisableAccess);

    BATT_STRONG_TYPEDEF(bool, DisableWrite);

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    template <typename... Args>
    static unsigned int translate_access(Args&&... args [[maybe_unused]]) noexcept
    {
        unsigned int access_rights = 0;

#if BATT_PLATFORM_IS_LINUX

        if (get_typed_arg(DisableAccess{false}, args...)) {
            access_rights |= PKEY_DISABLE_ACCESS;
        }
        if (get_typed_arg(DisableWrite{false}, args...)) {
            access_rights |= PKEY_DISABLE_WRITE;
        }

#endif  // BATT_PLATFORM_IS_LINUX

        return access_rights;
    }

    template <typename... Args>
    static StatusOr<ProtectedMemory> initialize(Args&&... args [[maybe_unused]]) noexcept
    {
        int pkey = -1;

#if BATT_PLATFORM_IS_LINUX

        pkey = pkey_alloc(/*flags(must be 0)=*/0, Self::translate_access(BATT_FORWARD(args)...));
        BATT_REQUIRE_OK(status_from_retval(pkey));

#endif  // BATT_PLATFORM_IS_LINUX

        return {ProtectedMemory{pkey}};
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    ProtectedMemory(const Self&) = delete;
    ProtectedMemory& operator=(const Self&) = delete;

    ProtectedMemory(Self&& other) noexcept : pkey_{std::exchange(other.pkey_, -1)}
    {
    }

    ~ProtectedMemory() noexcept
    {
#if BATT_PLATFORM_IS_LINUX
        if (this->pkey_ != -1) {
            BATT_CHECK_EQ(::pkey_free(this->pkey_), 0);
        }
#endif
    }

    Self& operator=(Self&& other) noexcept
    {
        if (this != &other) {
            this->pkey_ = std::exchange(other.pkey_, -1);
        }
        return *this;
    }

    template <typename... Args>
    Status set_access(Args&&... args [[maybe_unused]]) noexcept
    {
#if BATT_PLATFORM_IS_LINUX
        BATT_REQUIRE_OK(
            status_from_retval(::pkey_set(this->pkey_, Self::translate_access(BATT_FORWARD(args)...))));
#endif
        return OkStatus();
    }

    Status add_region(MutableBuffer buffer [[maybe_unused]]) noexcept
    {
#if BATT_PLATFORM_IS_LINUX
        BATT_REQUIRE_OK(status_from_retval(
            ::pkey_mprotect(buffer.data(), buffer.size(), PROT_READ | PROT_WRITE, this->pkey_)));
#endif
        return OkStatus();
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    //+++++++++++-+-+--+----- --- -- -  -  -   -

    explicit ProtectedMemory(int pkey [[maybe_unused]]) noexcept : pkey_{pkey}
    {
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    int pkey_ = -1;
};

}  // namespace batt
